INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-814ced5a-moex-00518', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「波特萊爾的詩：『老巴黎消失了／一座城市的形體，唉，有著比人心還要更快的變化。』所謂比 人心更快的變化，特別指向有限的、必定會消亡的生命。人必有死，相較於以磚石所造的城市，人 壽如此有限，而人的感受與念頭，又是人類經驗中變動最快的。波特萊爾走過巴黎街道時，如同被 電擊般意識到，他所居住的城市已經徹底失去其恆常特性，以讓人無從準備防備的速度，持續變化。 應該提供我們安穩依賴的磚石之物，背叛了我們的期待，翻身比我們念頭的轉換，變得更快更劇烈。」 下列選項，何者不是這段文章所要傳達的意旨？', '["建造城市所需的磚石之物，有恆常特性，永遠不會消失", "有限的、必定會消亡的生命，不只是人，還包括老巴黎", "我們以為人心變化很快，實際上城市的變化可能比人心還快", "作者最終要傳達的是，人心變動太快，把磚石穩固的城市也改變"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00519', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「凡不肯說謝謝的人，是一個驕傲冷橫的人，他覺得在這世界過的是『銀貨兩訖』的日子。他是工 商業社會的產物，他覺得他不欠誰，不求誰，他所擁有的東西都是他該得的，所以他不需要向誰說 『謝謝』。但我知道，我並不『該』得什麼，我曾赤手空拳來到這個世界，沒有人『該』愛我，沒 有人『該』養我，沒有人『該』為我廢寢忘食，出入攜抱。我也許繳了學費，但老師那份關懷器重 是我買得到的嗎？我也許付了米錢，但農夫的辛勞豈是我那一點錢報償得了的？」 「我曾赤手空拳來到這個世界」，「赤手空拳」的「赤」非指顏色，而有「空無一物」的意思。下 列選項，非指顏色的是：', '["「白」手起家", "「黃」梅時節", "「黑」布馬褂", "「綠」煙紅霧"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00520', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '承上題，本文意旨為：', '["凡事應心存感恩", "人不可錙銖必較", "禮貌使社會溫暖", "金錢絕不是萬能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00521', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「理想的下午，當消使在理想的地方，通常這地方是在城市。幽靜田村，風景美極，空氣水質好極， 卻是清晨夜晚都好，下午難免苦長。理想的下午，有賴理想的下午人。這類人樂意享受外間。樂意 暫且擱下手邊工作，樂意走出舒適的廳房、關掉柔美的音樂、闔上津津有味的書籍，套上鞋往外而 去。也只是漫無目的的走，看看市景，聽聽人聲。穿過馬路，登上台階，時而進入公園，看一眼花 草，瞧一眼池魚。揀一方大石或鐵椅坐下，不時側聽鄰客高談時政，嗅著飄來的香菸味，置之一笑。 有時翻閱小報，悄然睏去。醒來只覺眼前景物的色調略呈灰藍，像套了濾色鏡，不似先前那麼光燦 了，竟如同眾人散場多時只遺自己一個的那股辰光向晚寂寂。然一看錶，只過了十五分鐘。」 根據上文，下列何者最符合作者所謂「理想的下午」？', '["請假半天，在幽靜的山間園林尋幽訪勝", "暫時放下工作，帶一本小書到公園長椅上閒坐閱讀", "坐在城市的小咖啡廳，欣賞音樂與窗外風景，嗅著鄰座飄來的菸味", "帶著一顆悠閒的心，在城市中漫步閒坐，隨意地體驗城市中的百態"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00522', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '承上題，作者認為「理想的下午」應該發生在城市中，依引文推測，最可能的原因是什麼？', '["身處在熱鬧塵俗之中，正可以靜觀世間多種趣味", "偷得浮生半日閒，時間所限，難以探訪鄉間美景", "交通方便，商業活動頻繁，可以調劑無聊的午後", "城市中人來人往，個人做什麼都不至於感到孤寂"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00523', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '「財團法人國家文化藝術基金會」為辦理「國家文藝獎」，請全國文教機構與相關單位，推薦適當 人選，其使用之公文為：', '["簽", "呈", "咨", "函"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00524', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '下列公文中稱謂用語，何者正確？', '["對於上級機關，為表尊敬，應以「貴」稱之", "對於機關首長，為表尊敬，應以「臺端」稱之", "無論與其他機構有無隸屬關係，皆可用「本」自稱", "為尊重性別平權，不宜使用「先生」、「女士」，應一律稱「君」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00525', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '下列有關公文傳真的敘述，何者是錯誤的？', '["公文傳真應以原件為之，不宜用影印本傳真", "各機關因處理傳真公文需要之章戳，得自行刻用之", "完成陳核、繕校，未蓋用印信或簽署前，為爭取時效，得先行傳真", "傳真發文時，應先登錄傳真公文登記表（簿），記載相關事項、加蓋傳真作業人員名章及確認受 方電話、身分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00526', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '下列選項用語使用正確的是：', '["謝謝您惠賜大作，敝刊倍增光彩", "小犬身體不適，我代他向您請假", "國家政通人和，百姓應居安思危", "在下仁民愛物，是難能可貴之才 杯水車薪的物價，令人喘不過氣"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('elementary-814ced5a-moex-00527', 'elementary-814ced5a', 'elementary-814ced5a-moex-111-01c5eaab', 'sub-elementary-814ced5a-05', NULL, 'single_choice', '下列各選項「 」內的詞語，使用正確的是：', '["近日的芬普尼毒蛋事件，使食安問題再度「引人遐思」", "世大運慶功遊行，所到之處「萬人空巷」，高舉旗幟夾道歡迎", "強颱直撲的新聞發布後，民眾不敢「掉以輕心」，均謹慎防颱", "企業投下鉅資邀請知名影星為產品代言，希望能讓銷售量「推陳出新」 舉重選手於世大運奪得金牌並破世界紀錄的一刻，全場觀眾「破涕為笑」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:53+00:00", "source_pdf_sha1": "6590d4ee65e2", "answer_pdf_sha1": "e24c36da3da8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "505", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "圖書資訊管理"}'::jsonb, NULL)
